"""CI guard: detect module-scope mutations in test files.

Scans tests/**/*.py for dangerous patterns at module scope (not inside
function/class/if blocks) that cause test pollution:

- os.environ["KEY"] = ...        (env mutation without monkeypatch)
- app.dependency_overrides[...] = ...  (DI bypass)
- get_settings() = ... / get_settings() called then mutated (settings poisoning)
- sys.path.insert/append(...)    (import path manipulation)

Exits non-zero listing offending file:line when violations found.
Has a # noqa: test-isolation-ok escape hatch for intentional patterns.
"""

import ast
import sys
from pathlib import Path

# Patterns checked via AST — the scanner enforces module-scope only.
# The following patterns at module scope are violations:
#   - os.environ["KEY"] = VALUE  (any subscript assign on os.environ)
#   - app.dependency_overrides[KEY] = VALUE
#   - get_settings().X = VALUE
#   - sys.path.insert(...)
#   - sys.path.append(...)

# A line-level escape: a "# noqa: test-isolation-ok" comment on the same or
# preceding line disables the violation.
ESCAPE_MARKER = "# noqa: test-isolation-ok"


def _has_escape(lines: list[str], lineno: int) -> bool:
    """Check if a violation line or its immediate predecessor has an escape."""
    for i in [lineno - 2, lineno - 1]:  # 0-indexed
        if 0 <= i < len(lines) and ESCAPE_MARKER in lines[i]:
            return True
    return False


def check_file(path: Path) -> list[tuple[int, str]]:
    """Check a single test file for module-scope mutations. Returns [(line, msg)]."""
    text = path.read_text()
    lines = text.splitlines()
    try:
        tree = ast.parse(text, filename=str(path))
    except SyntaxError:
        return []  # Skip files that can't be parsed (e.g. empty)

    violations: list[tuple[int, str]] = []

    for node in ast.walk(tree):
        # Only module-level statements
        if not isinstance(node.parent if hasattr(node, "parent") else None, ast.Module):
            continue

    # Assign nodes at module scope
    for node in ast.iter_child_nodes(tree):
        if _has_escape(lines, node.lineno):
            continue

        # os.environ["KEY"] = VALUE  (AugAssign or Assign with Subscript)
        if isinstance(node, (ast.Assign, ast.AugAssign)):
            target = node.targets[0] if isinstance(node, ast.Assign) else node.target
            msg = _check_subscript_assign(target)
            if msg:
                violations.append((node.lineno, msg))
                continue

        # sys.path.insert(...) or sys.path.append(...)
        if isinstance(node, ast.Expr):
            call = _unwrap_call(node.value)
            if call and _is_syspath_mutation(call):
                violations.append((node.lineno, f"module-scope sys.path mutation"))
                continue

        # get_settings().attr = ... (not detectable as simple assign, covered by subscript)
        # Also check plain calls that are assigned — get_settings() result used later
        if isinstance(node, ast.Assign):
            # get_settings() assigned to a variable at module scope
            if isinstance(node.value, ast.Call):
                func = _unwrap_attr(node.value.func)
                if func and "get_settings" in func:
                    # Assigning get_settings() result at module scope
                    violations.append((node.lineno, "module-scope get_settings() call"))

        # app.dependency_overrides[key] = value (subscript Assign)
        # os.environ assignments
        # Both handled above via _check_subscript_assign

    # Re-parse manually without parent info for robustness
    # Do a second pass using direct child iteration
    for node in ast.iter_child_nodes(tree):
        if _has_escape(lines, node.lineno):
            continue

        if isinstance(node, ast.Assign):
            for target in node.targets:
                if isinstance(target, ast.Subscript):
                    subj = _unwrap_attr(target.value)
                    if subj:
                        if subj == "os.environ":
                            violations.append((node.lineno, "module-scope os.environ mutation"))
                        elif "app.dependency_overrides" in subj:
                            violations.append((node.lineno, "module-scope app.dependency_overrides mutation"))
                        elif subj == "get_settings":
                            violations.append((node.lineno, "module-scope get_settings() call"))

        elif isinstance(node, ast.Expr) and isinstance(node.value, ast.Call):
            call = node.value
            func_name = _get_call_name(call)
            if func_name and ("sys.path" in func_name and func_name.split(".")[-1] in ("insert", "append")):
                violations.append((node.lineno, "module-scope sys.path mutation"))

    return violations


def _unwrap_call(node):
    """Given a node, if it's a Call chain, return the outermost Call."""
    if isinstance(node, ast.Call):
        return node
    if isinstance(node, ast.Expr):
        return _unwrap_call(node.value)
    return None


def _is_syspath_mutation(call: ast.Call) -> bool:
    """Check if call is sys.path.insert or sys.path.append."""
    attr = _get_call_name(call)
    if attr and attr.startswith("sys.path."):
        method = attr.split(".")[-1]
        return method in ("insert", "append")
    return False


def _get_call_name(call: ast.Call) -> str | None:
    """Get the dotted name of a call (e.g. sys.path.insert)."""
    return _unwrap_attr(call.func)


def _unwrap_attr(node) -> str | None:
    """Get the dotted attribute chain as a string (e.g. os.environ)."""
    if isinstance(node, ast.Name):
        return node.id
    if isinstance(node, ast.Attribute):
        left = _unwrap_attr(node.value)
        if left is not None:
            return f"{left}.{node.attr}"
        return node.attr
    if isinstance(node, ast.Call):
        return _unwrap_attr(node.func)
    return None


def _check_subscript_assign(node) -> str | None:
    """Check for os.environ['key'] = val or app.dependency_overrides['key'] = val patterns."""
    if isinstance(node, ast.Subscript):
        subj = _unwrap_attr(node.value)
        if subj == "os.environ":
            return "module-scope os.environ mutation"
        if subj and "app.dependency_overrides" in subj:
            return "module-scope app.dependency_overrides mutation"
    return None


def main() -> int:
    test_root = Path("tests")
    violations: list[tuple[str, int, str]] = []  # (file, line, msg)

    for py_file in sorted(test_root.rglob("*.py")):
        file_violations = check_file(py_file)
        for line_no, msg in file_violations:
            violations.append((str(py_file), line_no, msg))

    if violations:
        print("FAIL: Module-scope mutations detected in test files:")
        print()
        for filepath, line_no, msg in violations:
            rel = Path(filepath).relative_to(".")
            print(f"  {rel}:{line_no}  {msg}")
        print()
        print("Fix: move these into fixtures (monkeypatch or ExitStack).")
        print(f"Total: {len(violations)} violation(s)")
        return 1

    print("OK: No module-scope mutations found in tests/")
    return 0


if __name__ == "__main__":
    sys.exit(main())
