def add_integration_marker(filepath: Path) -> bool:
    """Add @pytest.mark.integration to the first class or first test function."""
    text = filepath.read_text()
    lines = text.splitlines()

    # Skip if already has marker
    if "@pytest.mark.integration" in text:
        return False

    changes = 0

    # Strategy: find class definitions and add marker before them
    new_lines = list(lines)
    insert_positions = []

    for i, line in enumerate(new_lines):
        stripped = line.strip()
        # Match class definitions (not in docstrings)
        if stripped.startswith("class Test"):
            insert_positions.append(i)

    if insert_positions:
        # Insert before each class
        for idx in reversed(insert_positions):
            # Check if there's already a decorator above
            if idx > 0 and new_lines[idx - 1].strip().startswith("@"):
                # Skip - already has decorator(s)
                continue
            indent = " " * (len(line) - len(line.lstrip()))
            new_lines.insert(idx, f"{indent}@pytest.mark.integration")
            changes += 1

    if changes == 0:
        # No classes found - it might be module-level test functions
        # Add marker at line 6 (after imports)
