import ast
import re
from pathlib import Path

def add_module_level_marker(text: str, marker: str) -> str:
    """Add @pytest.mark.integration right before the first class/function definition at module scope.
    Inserts after all imports and docstrings, before the first test class or function."""
    lines = text.splitlines()

    if marker in text:
        return text  # already has marker

    # Find insert point: after last import/comment/docstring, before first class/func
    insert_at = None
    for i, line in enumerate(lines):
        stripped = line.strip()
        if stripped == "" or stripped.startswith("#") or stripped.startswith('"""') or stripped.startswith("from ") or stripped.startswith("import "):
            continue
        # First non-import, non-comment, non-blank line
        if stripped.startswith("class ") or stripped.startswith("def ") or stripped.startswith("@"):
            insert_at = i
            break

    if insert_at is None or insert_at == 0:
        # Try after first module docstring
        for i, line in enumerate(lines):
            if '"""' in line:
                continue
            if line.strip() == "":
                insert_at = i + 1
                break
        if insert_at is None:
            insert_at = len(lines)

    # Find proper indentation (0 for module level)
    new_lines = lines[:insert_at] + [""] + [f"@{marker}"] + lines[insert_at:]
    return "\n".join(new_lines) + "\n"


changed = []
for root in ["tests/integration", "tests/performance"]:
    for f in sorted(Path(root).rglob("test_*.py")):
        text = f.read_text()

        # Skip if already has marker
